CREATE TABLE public.payment_methods (id uuid DEFAULT gen_random_uuid() NOT NULL, type text NOT NULL, name text NOT NULL, is_active boolean NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL);
ALTER TABLE public.payment_methods ADD CONSTRAINT payment_methods_pkey PRIMARY KEY (id);
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.payment_methods TO anon;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.payment_methods TO authenticated;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.payment_methods TO service_role;
CREATE TABLE public.transaction_type (id bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL, name text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL);
ALTER TABLE public.transaction_type ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.transaction_type ADD CONSTRAINT transaction_type_pkey PRIMARY KEY (id);
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.transaction_type TO anon;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.transaction_type TO authenticated;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.transaction_type TO service_role;
CREATE TABLE public.transactions (id uuid DEFAULT gen_random_uuid() NOT NULL, title text NOT NULL, money real NOT NULL, notes text, created_at timestamp with time zone DEFAULT now() NOT NULL, payment_method uuid DEFAULT gen_random_uuid() NOT NULL, type text NOT NULL);
ALTER PUBLICATION supabase_realtime ADD TABLE public.transactions;
COMMENT ON TABLE public.transactions IS 'this where the user enter their records for expenses and incomes';
ALTER TABLE public.transactions ADD CONSTRAINT records_pkey PRIMARY KEY (id);
ALTER TABLE public.transactions ADD CONSTRAINT transactions_payment_method_fkey FOREIGN KEY (payment_method) REFERENCES public.payment_methods(id) ON UPDATE CASCADE ON DELETE SET NULL;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.transactions TO anon;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.transactions TO authenticated;
GRANT MAINTAIN, REFERENCES, TRIGGER, TRUNCATE ON public.transactions TO service_role;
